200 // {get,set}LoopEstimatedTripCount implement special handling of zero.
201 TEST(LoopUtils, zeroEstimatedTripCount) {
202   LLVMContext C;
203   const char *IR =
204       "define void @foo(i1 %c) {\n"
205       "entry:\n"
206       "  br label %loop0\n"
207       "loop0:\n"
208       "  br i1 %c, label %loop0, label %loop1\n"
209       "loop1:\n"
210       "  br i1 %c, label %loop1, label %loop2, !llvm.loop !1\n"
211       "loop2:\n"
212       "  br i1 %c, label %loop2, label %exit, !prof !5, !llvm.loop !2\n"
213       "exit:\n"
214       "  ret void\n"
215       "}\n"
216       "!1 = distinct !{!1, !3}\n"
217       "!2 = distinct !{!2, !3, !4}\n"
218       "!3 = !{!\"foo\", i32 5}\n"
219       "!4 = !{!\"llvm.loop.estimated_trip_count\", i32 10}\n"
220       "!5 = !{!\"branch_weights\", i32 1, i32 9}\n"
221       "\n";
222 
223   // With EstimatedLoopInvocationWeight, setLoopEstimatedTripCount sets branch
224   // weights and llvm.loop.estimated_trip_count all to 0, so
225   // getLoopEstimatedTripCount returns std::nullopt.  It does not touch other
226   // loop metadata, if any.
227   std::unique_ptr<Module> M = parseIR(C, IR);
228   run(*M, "foo",
229       [&](Function &F, DominatorTree &DT, ScalarEvolution &SE, LoopInfo &LI) {
230         assert(LI.end() - LI.begin() == 3 && "Expected three loops");
231         for (Loop *L : LI) {
232           Instruction &LatchBranch = *L->getLoopLatch()->getTerminator();
233           std::optional<int> Foo = getOptionalIntLoopAttribute(L, "foo");
234 
