236                         L, 0, /*EstimatedLoopInvocationWeight=*/1),
237                     true);
238 
239           SmallVector<uint32_t, 2> Weights;
240           EXPECT_EQ(extractBranchWeights(LatchBranch, Weights), true);
241           EXPECT_EQ(Weights[0], 0u);
242           EXPECT_EQ(Weights[1], 1u);
